sql_query:
SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Type of combination" = 'ICI+BRAFi+MEKi';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Treatment regimen" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Type of combination" = 'ICI+BRAFi+MEKi'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_braf_inhibitor(source_value) AS "braf_inhibitor", derive_mek_inhibitor(source_value) AS "mek_inhibitor"
FROM base;
